Javascript.isReadOnly:
if (null != WP && null != WP.GetScreenProcess && null != WP.GetScreenProcess()) { 
				var localNumber = WPU.getValue("/params/param[@name='xml']/ds/Warrant/LocalNumber");
				if (localNumber == "" || localNumber == null) return true; }

Javascript.initialise:
var partyAgainstNumber = WPU.getValue("/params/param[@name='xml']/WarrantReturn/PartyAgainstNumber");
var def1Addr3 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant1/Address/Line[3]");
var def2Addr3 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant2/Address/Line[3]");
var partyAgainstAddr3 = "";
if(partyAgainstNumber == 1) {
	partyAgainstAddr3 = def1Addr3;
} else {
	partyAgainstAddr3 = def2Addr3; }
var otherPossessAddr3 = WPU.getValue("/params/param[@name='xml']/ds/ManageCase/OtherPossessionAddress/Address/Line[3]");
var possessAddr3 = "";
if(otherPossessAddr3 != "") {
	possessAddr3 = otherPossessAddr3;
} else {
	possessAddr3 = partyAgainstAddr3; }
Services.setValue(PossessAdLine3.dataBinding, possessAddr3);
